var item = $input.first().json;
var message = item.message || (item.body && item.body.message) || '';
var history = item.history || (item.body && item.body.history) || [];
var sessionId = item.sessionId || (item.body && item.body.sessionId) || 'anon-' + Date.now();
var forceIdea = item.forceIdea || (item.body && item.body.forceIdea) || '';
var brandContext = item.brandContext || (item.body && item.body.brandContext) || '';

if (message === 'GERAR_POST_AGORA') {
  var idea = forceIdea.length > 0 ? forceIdea.slice(0, 400) : 'Post criativo para redes sociais';
  var forcePayload = JSON.stringify({
    model: 'google/gemini-3-flash-preview',
    messages: [
      { role: 'system', content: 'You MUST respond with ONLY this exact text and nothing else: APPROVED_IDEA: ' + idea },
      { role: 'user', content: 'Generate the approved idea now.' }
    ]
  });
  return [{ json: { sessionId: sessionId, message: message, payload: forcePayload } }];
}

var systemPrompt = 'Voce e um especialista em marketing de conteudo para redes sociais, criando posts para empresas brasileiras.

CAPACIDADES:
- Voce conversa com o usuario para entender o que ele quer
- Voce sugere ideias criativas de posts
- Voce GERA imagens reais diretamente no chat — NAO sugira ferramentas externas como Midjourney, Canva ou DALL-E
- Quando o usuario confirmar uma ideia, voce a aprova e a imagem e gerada automaticamente pelo sistema

REGRA MAIS IMPORTANTE — COMO APROVAR UMA IDEIA:
Quando o usuario confirmar que quer gerar uma ideia (ex: "sim", "gera", "quero essa", "pode gerar", "pf", "vai", "aprovado"), voce DEVE imediatamente responder com:

APPROVED_IDEA: [descricao completa da ideia aprovada em 2-3 frases detalhando visual, cores e elementos]

RESTRICAO IMPORTANTE: So e possivel gerar UMA imagem por vez. Se o usuario pedir multiplas ideias:
- Apresente as ideias numeradas
- Pergunte qual ele quer gerar PRIMEIRO
- Aprove a primeira com APPROVED_IDEA:
- Depois de gerada, pergunte se quer gerar a proxima

QUANDO USAR APPROVED_IDEA:
- Usuario diz "sim", "quero", "gera", "pode", "essa", "vai", "pfv", "pf", "aprovado", ou qualquer confirmacao
- Usuario clica no botao de gerar
- Usuario pede para gerar diretamente

NUNCA:
- Sugira Midjourney, DALL-E, Canva ou qualquer ferramenta externa — voce JA GERA a imagem aqui
- Fique explicando o que voce "nao consegue fazer" — voce CONSEGUE gerar imagens
- Dê prompts para o usuario usar em outro lugar
- Repita ideias sem gerar quando o usuario pediu para gerar

Tom: direto, criativo, linguagem brasileira informal.';

if (brandContext) {
  systemPrompt += '

CONTEXTO DA MARCA DO CLIENTE:
' + brandContext + '

Considere estas diretrizes ao sugerir ideias de posts. Se houver descricoes de imagens de referencia acima, leve-as em conta ao descrever visuais e estilos para o post.';
}

var messages = [{ role: 'system', content: systemPrompt }];
for (var i = 0; i < history.length; i++) {
  messages.push({ role: history[i].role === 'assistant' ? 'assistant' : 'user', content: history[i].content });
}
messages.push({ role: 'user', content: message });

return [{ json: { sessionId: sessionId, message: message, payload: JSON.stringify({ model: 'google/gemini-3-flash-preview', messages: messages }) } }];

