={{ (function() {
  var idea = $json.approvedIdea;
  var ctx = $json.brandContext || '';
  var prompt = (ctx ? ctx + '\n\n' : '')
    + 'Create a detailed image generation prompt in English for a social media post about: ' + idea + '.'
    + (ctx ? ' Respect the brand guidelines and visual references provided above.' : '')
    + ' Respond with ONLY the prompt text. Style: professional photography or digital art, vibrant colors, social media ready, 1:1 ratio, no text overlays.';
  return JSON.stringify({ model: 'google/gemini-3-flash-preview', messages: [{ role: 'user', content: prompt }] });
})() }}

