var resp = $input.first().json;
var imagePrompt = (resp.choices && resp.choices[0] && resp.choices[0].message) ? resp.choices[0].message.content.trim() : 'professional social media post, vibrant colors';
var prev = $('Extrair Ideia').first().json;
var incoming = $('Receber Mensagem').first().json;
return [{ json: { imagePrompt: imagePrompt, approvedIdea: prev.approvedIdea, sessionId: prev.sessionId, brandContext: incoming.brandContext || '' } }];

var imageResp = $('Gerar Imagem').first().json;
var images = imageResp.choices && imageResp.choices[0] && imageResp.choices[0].message && imageResp.choices[0].message.images;
var imageUrl = (images && images[0] && images[0].image_url) ? images[0].image_url.url : '';

var captionResp = $input.first().json;
var rawText = (captionResp.choices && captionResp.choices[0] && captionResp.choices[0].message) ? captionResp.choices[0].message.content : '{}';
var caption = ''; var hashtags = [];
try {
  var start = rawText.indexOf('{');
  var end = rawText.lastIndexOf('}');
  var clean = (start !== -1 && end !== -1) ? rawText.slice(start, end + 1) : rawText;
  var p = JSON.parse(clean);
  caption = p.caption || '';
  hashtags = p.hashtags || [];
} catch(e) {
  caption = rawText;
  hashtags = [];
}
var prev = $('Preparar Geracao').first().json;
return [{ json: { imageUrl: imageUrl, caption: caption, hashtags: hashtags, approvedIdea: prev.approvedIdea, sessionId: prev.sessionId } }];
